import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import get_asset_entity_path, resolve_cfg

class PrismGetAssetsByTypeNode(BaseNode):
    name = "Prism: Get Assets by Type"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("project", "dict")
        self.add_input("asset_type", "dict")
        self.add_output("assets", "list")
        self.add_output("asset", "dict")
        self.add_output("entity", "dict")
        self.add_output("count", "int")
        self.add_output("found", "bool")

    def _project_path(self, project):
        path = project.get('project_path', '')
        if not path:
            cfg = project.get('configPath', '')
            if cfg:
                path = os.path.dirname(os.path.dirname(cfg))
        return path

    def _switch_project(self, core, project):
        path = self._project_path(project)
        if not path:
            self.log_error('Cannot determine project path from project dict.')
            return False
        try:
            core.changeProject(path)
            return True
        except Exception as e:
            self.log_error(f'changeProject failed: {e}')
            return False

    def _asset_category(self, asset):
        asset_path = asset.get('asset_path', asset.get('name', ''))
        if asset_path:
            return asset_path.replace('\\', '/').split('/')[0].lower()
        return ''

    def _build_entity(self, asset, core=None, project_path=''):
        asset_path = asset.get('asset_path', asset.get('name', ''))
        path = asset.get('path', '')
        if not path:
            for key in ('localPath', 'global_path', 'filepath', 'entity_path'):
                path = asset.get(key, '')
                if path:
                    break
        if not path:
            paths_dict = asset.get('paths', {})
            if isinstance(paths_dict, dict):
                path = (paths_dict.get('global', '')
                        or paths_dict.get('local', '')
                        or next((v for v in paths_dict.values() if isinstance(v, str) and v), ''))
        if not path and project_path:
            cfg = resolve_cfg(core=core)
            path = get_asset_entity_path(asset, project_path, core=core, cfg_path=cfg)
        return {
            'type': 'asset',
            'asset_path': asset_path,
            'path': path,
            'location': asset.get('location', 'global'),
            'paths': asset.get('paths', {}),
        }

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        project = inputs.get('project') or {}
        asset_type_obj = inputs.get('asset_type') or {}
        asset_type = (asset_type_obj.get('name', '') or '').strip().lower()

        empty = {'assets': [], 'asset': {}, 'entity': {}, 'count': 0, 'found': False}
        if core is None:
            self.log_error('No PrismCore found.')
            return empty
        if not project:
            self.log_error('No project provided.')
            return empty
        if not asset_type:
            self.log_error('No asset_type provided or missing name field.')
            return empty
        if not self._switch_project(core, project):
            return empty

        try:
            all_assets = list(core.entities.getAssets() or [])
        except Exception as e:
            self.log_error(f'getAssets failed: {e}')
            return empty

        matches = [a for a in all_assets if self._asset_category(a) == asset_type]
        best = matches[0] if matches else {}
        proj_path = self._project_path(project)
        entity = self._build_entity(best, core=core, project_path=proj_path) if best else {}
        self.log_info(
            f"Found {len(matches)} '{asset_type}' asset(s) in '{project.get('name', '')}' "
            f"(total: {len(all_assets)})"
        )
        return {'assets': matches, 'asset': best, 'entity': entity,
                'count': len(matches), 'found': bool(matches)}

def register_node():
    return PrismGetAssetsByTypeNode
